window.bookSummaryJSON = "<p><b>For over 60 years, readers of all ages have been enchanted by the magical realms, the epic battles between good and evil, and the unforgettable creatures of Narnia.</b></p> <p>This box set includes all seven titles in <i>The Chronicles of Narnia - The Magician's Nephew</i>; <i>The Lion, the Witch, and the Wardrobe</i>; <i>The Horse and His Boy</i>; <i>Prince Caspian</i>; <i>The Voyage of the Dawn Treader</i>; <i>The Silver Chair</i>; and <i>The Last Battle</i>.</p>"; 
